import { useState } from "react";

const NotFound = () => {
  const [isClicked, setIsClicked] = useState(false);
  const handleClick = () => {
    setIsClicked(true);
  };

  return (
    <div>
      <h1>404 Not Found.</h1>
      <button
        className="bg-blue-500 text-white rounded-md px-3 py-1"
        onClick={handleClick}
      >
        Go To Home
      </button>
      {isClicked && <navigate to="/" />}
    </div>
  );
};

export default NotFound;
